package handlers

import (
	"testing"
)

func FuzzGreetingHandler(f *testing.F) {
	// Add fuzzing tests for name sanitization
	f.Fuzz(func(t *testing.T, name string) {
		token := testhelpers.SignedTokenForUser(name)
		req := httptest.NewRequest("GET", "/greeting", nil)
		req.Header.Set("Authorization", "Bearer "+token)

		rr := httptest.NewRecorder()
		GreetingHandler(rr, req)

		// Ensure we don't panic and return a valid status code
		if rr.Code != http.StatusOK && rr.Code != http.StatusBadRequest {
			t.Errorf("unexpected status code: %d", rr.Code)
		}
	})
}
